cd /app && python3 -c "
import torch
sd=torch.load('weights.pt')
ks=list(sd.keys())
print('total keys', len(ks))
# count layers
enc=set(); dec=set()
for k in ks:
    if k.startswith('transformer_encoder.layers.'):
        enc.add(int(k.split('.')[2]))
    if k.startswith('transformer_decoder.layers.'):
        dec.add(int(k.split('.')[2]))
print('enc layers', sorted(enc))
print('dec layers', sorted(dec))
d=torch.load('dataset.pt')
print(type(d))
if isinstance(d,dict):
    for k,v in d.items(): print(k, type(v), getattr(v,'shape',None), getattr(v,'dtype',None))
elif isinstance(d,(list,tuple)):
    for i,v in enumerate(d): print(i, type(v), getattr(v,'shape',None), getattr(v,'dtype',None))
" 2>/dev/null

